import React, { useEffect, useState } from 'react';
import { getDashboardStats } from '../services/api';
import { format } from 'date-fns';

export default function AdminActivityLog() {
  const [logs, setLogs] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getDashboardStats().then(({ data }) => { setLogs(data.recentLogs || []); setLoading(false); }).catch(() => setLoading(false));
  }, []);

  return (
    <div className="space-y-5">
      <h2 className="text-2xl font-display font-bold text-gray-900 dark:text-white">Activity Log</h2>
      <div className="bg-white dark:bg-gray-800 rounded-2xl border border-gray-100 dark:border-gray-700 shadow-sm p-6">
        {loading ? <div className="text-center text-gray-400 py-8">Loading...</div> : logs.length === 0 ? (
          <div className="text-center text-gray-400 py-8">No activity recorded yet.</div>
        ) : (
          <div className="relative">
            <div className="absolute left-2.5 top-0 bottom-0 w-0.5 bg-gray-100 dark:bg-gray-700" />
            <div className="space-y-5">
              {logs.map((log, i) => (
                <div key={i} className="flex gap-4 pl-8 relative">
                  <div className="absolute left-0 w-5 h-5 rounded-full bg-indigo-600 border-2 border-white dark:border-gray-800 top-0.5" />
                  <div className="flex-1">
                    <p className="text-sm font-medium text-gray-900 dark:text-white">{log.action}</p>
                    <p className="text-sm text-gray-600 dark:text-gray-400 mt-0.5">{log.details}</p>
                    <p className="text-xs text-gray-400 mt-1">{format(new Date(log.createdAt), 'MMM d, yyyy • h:mm a')}</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
